export function getTopicClusterBySlug(slug: string): TopicCluster | undefined {
  return TOPIC_CLUSTERS.find((t) => t.slug === slug);
}

export function getRelatedTopicClusters(slugs: string[]): TopicCluster[] {
  return TOPIC_CLUSTERS.filter((t) => slugs.includes(t.slug));
}
